-- 2026-06-19: shoulder_rcr_subscapularis — фазы «Путь» + структурированные критерии перехода.
-- Протокол восстановления после операции по шву подлопаточной мышцы плеча (изолированный шов).
--
-- Источник: PROTOCOLS досье шва подлопаточной мышцы + PROTOCOLS/shoulder/_extractions.json
-- (suggested_program_type_code='shoulder_rcr_subscapularis'). 5 фаз: 1 Максимальная защита →
-- 2 Возврат активного движения → 3 Сила → 4 Мощность → 5 Возврат к спорту (терминальная).
-- Контент в ПАЦИЕНТСКОМ регистре (без клинич. жаргона PROM/AROM/ER/IR/MMT/MVIC/LSI/DASH/CKCUEST —
-- раскрыт обычными словами: «наружная ротация», «внутренняя ротация», «сила по сравнению со
-- здоровой рукой» и т.п.). Vadim калибрует через AdminContent.
--
-- СУБСКАПУЛЯРИС-СПЕЦИФИКА (главное отличие от прочих протоколов плеча): подлопаточная мышца —
-- внутренний ротатор, и именно НАРУЖНАЯ ротация плеча натягивает свежий шов. Поэтому главная
-- защита — ОГРАНИЧЕНИЕ НАРУЖНОЙ РОТАЦИИ (в первые недели почти запрещена, расширяется по графику),
-- а силовую внутреннюю ротацию вводят отсрочено (примерно с 12 недели). В пациентском тексте это
-- объясняется простым языком: «поворот руки наружу» / «поворот руки внутрь, к животу».
--
-- criteria_next (free-text на rehab_phases) дублирует метки критериев → пациент видит их СРАЗУ
-- в «Пути». Структурированная phase_transition_criteria — для будущей авто-проверки (слот D2).
--
-- Классификация критериев: авто-проверяемо сегодня только боль ВАШ → criterion_type
-- 'measurement' (measurement_type='vas_score', source='pain' — единый код против pain_entries.vas_score).
-- Числовые пороги ROM/силы/функциональных тестов система не хранит → 'instructor_check' с порогом
-- в ТЕКСТЕ label (куратор вводит очно). Качественное да/нет от пациента → 'self_report'.
-- Фаза 5 (возврат к спорту) — терминальная, transition_criteria пуст → её строки в WITH НЕ включены.
--
-- Идемпотентна: ON CONFLICT DO NOTHING для обеих таблиц (AdminContent = источник истины после
-- деплоя; ручная калибровка не затирается). Прогон тест-цикла createdb→schema→migrations×2 → ок.
-- НЕ трогает acl/knee_*/другие program_type (разные program_type/phase_id).

BEGIN;

-- =====================================================
-- 1. Фазы shoulder_rcr_subscapularis (контент «Путь»)
-- =====================================================
INSERT INTO rehab_phases (program_type, phase_number, title, subtitle, duration_weeks, description, goals, restrictions, criteria_next, icon, color, color_bg, teaser, allowed, pain, daily, red_flags, faq)
VALUES
(
    'shoulder_rcr_subscapularis', 1,
    'Максимальная защита',
    'Первые 0–4 недели',
    '0-4',
    'Самый ранний этап после операции. Шов ещё совсем свежий, поэтому главная задача — защитить его и дать тканям прижиться. Плечо носят в специальной повязке (слинге), боль и отёк берут под контроль, а движения выполняет помощник или здоровая рука — без вашего собственного усилия. Особенно важно не поворачивать руку наружу: именно это движение натягивает шов.',
    '["Максимально защитить шов и дать тканям зажить","Снизить боль и отёк","Аккуратно вернуть пассивную подвижность, не превышая разрешённый поворот наружу","Освоить простые бытовые действия в повязке"]',
    '["Не поворачивайте руку наружу больше разрешённого предела — первые недели это движение под особым запретом","Не заводите руку за спину (поворот внутрь к пояснице) в первые недели","Никаких самостоятельных активных движений плечом и усилий рукой","Не опирайтесь на больную руку и не несите ей вес","Носите повязку с отводящей подушкой днём и ночью, как назначил врач"]',
    '["Боль в покое стала небольшой (до 3 из 10)","Помощник свободно поднимает руку вперёд примерно до 120°","Помощник отводит руку в сторону примерно до 90°","Получается выполнять простые дела на уровне пояса","Сон нарушен несильно","Рана зажила нормально (оценка куратора)"]',
    'shield', '#EF4444', '#FEF2F0',
    'Защитить шов, снять боль и отёк, носить повязку',
    '["Пассивные движения в пределах ограничений: подъём вперёд, маятник, скольжение руки по столу","Свободные движения кисти, запястья и локтя","Мягкая работа с лопаткой","Холод (лёд через ткань) при отёке","Повязка с отводящей подушкой днём и ночью"]',
    '["Умеренная боль и ночной дискомфорт в первые недели — это нормально","Ориентир для перехода дальше — боль в покое меньше 3 из 10","Лёд прикладывайте через ткань, не напрямую на кожу"]',
    '["Несколько коротких занятий в день лучше одного длинного","Держите руку в повязке, снимайте только для разрешённых упражнений и гигиены","В покое подкладывайте опору под локоть, чтобы плечо отдыхало"]',
    '["Повышение температуры, покраснение, выделения из раны — признаки инфекции, срочно к врачу","Онемение или слабость в кисти","Неконтролируемая, очень сильная боль","Внезапная потеря возможности двигать рукой"]',
    '[{"q":"Почему нельзя двигать рукой самому?","a":"Шов подлопаточной мышцы ещё очень свежий. Любое собственное усилие, особенно поворот руки наружу, натягивает его и мешает заживать. Поэтому в первые недели руку двигает помощник или здоровая рука."},{"q":"Зачем такая строгая повязка?","a":"Отводящая подушка держит плечо в положении, где шов меньше всего натягивается. Это защищает результат операции в самый уязвимый период."},{"q":"Почему именно поворот наружу под запретом?","a":"Подлопаточная мышца поворачивает руку внутрь. Когда плечо разворачивают наружу, эта мышца и её свежий шов растягиваются сильнее всего — поэтому наружный поворот ограничивают строже остальных движений."}]'
),
(
    'shoulder_rcr_subscapularis', 2,
    'Возврат активного движения',
    'Примерно 4–8 недели',
    '4-8',
    'Шов окреп достаточно, чтобы начать двигать рукой самостоятельно — сначала в облегчённых положениях, где сила тяжести почти не мешает. Постепенно возвращаем полный объём движений и учим мышцы плеча и лопатки работать слаженно. Поворот руки наружу всё ещё ограничен, особенно при поднятой руке.',
    '["Плавно перейти к самостоятельным движениям рукой","Вернуть полный подъём руки вперёд","Развить выносливость мышц плеча и лопатки","Восстановить слаженную работу плеча без компенсаций"]',
    '["Не поворачивайте руку наружу при поднятой в сторону руке — в этом положении шов натягивается сильнее всего","Никаких рывков и форсированного растяжения","Не поднимайте тяжести и не делайте упражнений с сопротивлением","Не делайте упражнений на силу поворота руки внутрь"]',
    '["Боль при движении небольшая (до 3 из 10)","Самостоятельно поднимаете руку вперёд примерно до 120°","Поворот руки наружу (рука у тела) дошёл примерно до 45°","Сон почти не нарушен","Движение плеча и лопатки ровное, без перекосов и компенсаций"]',
    'dumbbell', '#F59E0B', '#FFF8ED',
    'Самостоятельные движения и выносливость мышц',
    '["Самостоятельные движения в облегчённых положениях","Полный пассивный подъём руки вперёд; поворот наружу у тела и при небольшом отведении — до разрешённого предела","Лёгкие упражнения без веса","Изометрия лопатки, мягкая работа задних мышц плеча","Повязку днём убирают, ночью носят до 6 недели"]',
    '["Лёгкая боль при движении допустима","Ориентир для перехода — боль меньше 3 из 10 при самостоятельных движениях","Нарастающая боль или отёк — сигнал снизить нагрузку"]',
    '["Занимайтесь короткими подходами несколько раз в день","Двигайтесь плавно, без рывков","Следите, чтобы плечо не подтягивалось вверх при подъёме руки"]',
    '["Те же тревожные признаки, что и на первом этапе","Внезапный щелчок в плече с резкой потерей силы — возможный повторный разрыв шва, срочно к врачу"]',
    '[{"q":"Можно ли уже снимать повязку?","a":"Днём повязку обычно убирают примерно с 4 недели, а на ночь оставляют до 6 недели. Точные сроки задаёт ваш хирург."},{"q":"Почему всё ещё нельзя поворачивать руку наружу при поднятой руке?","a":"Когда рука отведена в сторону и одновременно разворачивается наружу, натяжение на шов подлопаточной мышцы максимально. Это положение вводят позже и постепенно."}]'
),
(
    'shoulder_rcr_subscapularis', 3,
    'Сила',
    'Примерно 8–12 недели',
    '8-12',
    'Шов зажил достаточно, чтобы начать укреплять мышцы. Сначала лёгкие усилия, затем упражнения с небольшим сопротивлением. Подвижность доводим почти до уровня здоровой руки. Силовые упражнения на поворот руки внутрь (к животу) подключают ближе к концу этого этапа — примерно с 12 недели.',
    '["Начать укрепление мышц плеча","Довести подвижность почти до уровня здоровой руки","Аккуратно, дозированно нагружать зону шва"]',
    '["Не поднимайте больше примерно 2 кг этой рукой","Силовые упражнения на поворот руки внутрь — не раньше 12 недели","Не форсируйте поворот руки наружу"]',
    '["Подвижность больше 90% от здоровой руки","Сила руки восстановилась хотя бы до 80% от здоровой (для спортсменов)","Сила поворота наружу составляет больше 70% от силы поворота внутрь","Сила мышц при ручной проверке выше 4 из 5","Рука почти не ограничивает повседневные дела","Боль при упражнениях с сопротивлением меньше 3 из 10","Справляетесь со всеми домашними делами"]',
    'activity', '#3B82F6', '#EFF7FD',
    'Укрепление мышц и почти полная подвижность',
    '["Пассивные движения во всех направлениях без форсирования поворота наружу","Переход от лёгких усилий к упражнениям с сопротивлением","Начальное укрепление зоны шва небольшой нагрузкой","Мягкое растяжение на поворот руки внутрь (рука за спину) примерно с 8 недели","Велотренажёр и лёгкий бег примерно с 12 недели"]',
    '["Ориентир — боль меньше 3 из 10 при упражнениях с сопротивлением","Боль на нагрузке держите на низком уровне","Острая боль — сигнал остановиться и сообщить куратору"]',
    '["Наращивайте вес очень постепенно","Чередуйте силовые и восстановительные дни","Следите, чтобы отёк уходил к утру"]',
    '["Внезапная потеря силы при повороте руки внутрь","Возврат боли в передней части плеча","Ощущение неустойчивости или «соскальзывания» в плече"]',
    '[{"q":"Почему силу поворота внутрь начинают так поздно?","a":"Поворот руки внутрь — главная работа подлопаточной мышцы. Силовая нагрузка на это движение раньше времени может перегрузить ещё не до конца окрепший шов, поэтому её вводят примерно с 12 недели."},{"q":"Нормально ли, что мышцы стали слабее?","a":"Да. После периода покоя мышцы слабеют, и сила возвращается постепенно при регулярных занятиях. На это уходят недели и месяцы — это ожидаемо."}]'
),
(
    'shoulder_rcr_subscapularis', 4,
