    '["Вернуться к полной спортивной активности без боли и ограничений","Сохранять силу, подвижность и контроль движений плеча"]',
    '["Возврат к спорту — не раньше шести месяцев с операции","Прыжковые и ударные упражнения на руку — не раньше 18 недели","Финальное решение о возврате принимается вместе с куратором и врачом"]',
    '[]',
    'trophy', '#EC4899', '#FFF9E6',
    'Полный возврат к спорту и активной жизни',
    '["Полноценные силовые упражнения: жимы, отжимания, тяги","Координационные диагональные движения","Прыжковые и ударные нагрузки на руку примерно с 18 недели","Возврат к навыкам своего вида спорта по готовности"]',
    '["Цель — полная активность без боли","Плечо не должно отекать после нагрузки","Возврат боли или неустойчивости — стоп и к куратору"]',
    '["Не бросайте поддерживающие упражнения даже на пике формы","Разминка перед нагрузкой обязательна","Прислушивайтесь к плечу — уверенность в движении важна не меньше силы"]',
    '["Возврат боли при нагрузке","Внезапная потеря силы при повороте руки внутрь или щелчок в плече — срочно к врачу"]',
    '[{"q":"Почему нельзя вернуться к спорту раньше, если рука кажется здоровой?","a":"Тканям шва нужно время на полное созревание. Возврат к нагрузкам раньше достаточного срока повышает риск повторного разрыва, даже если сила и подвижность уже хорошие."},{"q":"Можно ли совсем перестать делать упражнения?","a":"Поддерживающие упражнения на силу и контроль движений стоит сохранить надолго — они закрепляют результат и берегут плечо от перегрузок."}]'
)
ON CONFLICT (program_type, phase_number) DO NOTHING;

-- =====================================================
-- 2. Структурированные критерии перехода shoulder_rcr_subscapularis
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 5 терминальная (transition_criteria пуст) — в WITH НЕ включена.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (максимальная защита → возврат активного движения)
  (1, 'pain_rest_lt3_p1',     'Боль в покое меньше 3 из 10',                                               'measurement',      'vas_score'::varchar, 'pain'::varchar, '<='::varchar, 3::numeric, NULL::numeric, 7::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'flexion_120_p1',       'Подъём руки вперёд (с помощью) не менее 120°',                              'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'abduction_90_p1',      'Отведение руки в сторону (с помощью) не менее 90°',                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
