  (3, 'er_ir_ratio_70_p3',    'Сила поворота наружу больше 70% от силы поворота внутрь',                    'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'mmt_gt4_p3',           'Сила мышц при ручной проверке выше 4 из 5',                                  'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
