  (4, 'shot_put_90_p4',       'Бросковый тест одной рукой больше 90% от здоровой руки',                     'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, TRUE),
  (4, 'ckcuest_gt21_p4',      'Тест на опору и устойчивость плеча — более 21 касания за 15 секунд',         'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, TRUE),
